// src/pages/RiderRegister.jsx
import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  Grid,
  Modal,
  Box,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { signupRider, uploadRiderDocs } from "../services/api";

export default function RiderRegister() {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ fullName: "", email: "", mobile: "" });
  const [docs, setDocs] = useState({ aadharFront: null, aadharBack: null, license: null });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [openModal, setOpenModal] = useState(false);

  const handleChange = (e) => setFormData(prev => ({ ...prev, [e.target.name]: e.target.value }));
  const handleFileChange = (e) => {
    const { name, files } = e.target;
    setDocs(prev => ({ ...prev, [name]: files[0] }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(""); setLoading(true);
    try {
      const res = await signupRider(formData);
      if (!res.data?.success) { setError(res.data?.message || "Signup failed."); setLoading(false); return; }
      const riderId = res.data?.data?.id;
      if (!riderId) { setError("No Rider ID returned."); setLoading(false); return; }

      const formDataUpload = new FormData();
      formDataUpload.append("aadharFront", docs.aadharFront);
      formDataUpload.append("aadharBack", docs.aadharBack);
      formDataUpload.append("license", docs.license);
      await uploadRiderDocs(riderId, formDataUpload);

      setOpenModal(true);
      setTimeout(() => { setOpenModal(false); navigate("/rider-login"); }, 3000);
    } catch (err) {
      console.error(err); setError("Server error. Try again."); 
    } finally { setLoading(false); }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ mt: 6, p: 5, borderRadius: 4, boxShadow: 3 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2, textAlign: "center" }}>Rider Signup</Typography>
        <Typography variant="body2" sx={{ mb: 3, color: "gray", textAlign: "center" }}>
          Create your account and upload documents.
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <form onSubmit={handleSubmit}>
          <TextField fullWidth label="Full Name" name="fullName" value={formData.fullName} onChange={handleChange} margin="normal" required />
          <TextField fullWidth type="email" label="Email" name="email" value={formData.email} onChange={handleChange} margin="normal" required />
          <TextField fullWidth type="tel" label="Mobile Number" name="mobile" value={formData.mobile} onChange={handleChange} margin="normal" inputProps={{ maxLength: 10 }} required />

          <Typography variant="h6" sx={{ mt: 3, mb: 1 }}>Upload Documents</Typography>
          <Grid container spacing={2}>
            {["aadharFront","aadharBack","license"].map((field) => (
              <Grid item xs={12} key={field}>
                <Button variant="outlined" component="label" fullWidth>
                  {field === "aadharFront" ? "Aadhar Front" : field === "aadharBack" ? "Aadhar Back" : "License"}
                  <input type="file" name={field} hidden onChange={handleFileChange} required />
                </Button>
                {docs[field] && <Typography sx={{ mt: 0.5 }}>{docs[field].name}</Typography>}
              </Grid>
            ))}
          </Grid>

          <Button type="submit" fullWidth variant="contained" sx={{ mt: 4, bgcolor: "black", color: "white", fontWeight: "bold" }} disabled={loading}>
            {loading ? "Submitting..." : "Sign Up"}
          </Button>
        </form>

        <Typography sx={{ mt: 3, textAlign: "center" }}>
          Already have an account? <Button onClick={() => navigate("/rider-login")} sx={{ fontWeight: "bold" }}>LOGIN</Button>
        </Typography>
      </Paper>

      <Modal open={openModal}>
        <Box sx={{ position: "absolute", top: "50%", left: "50%", transform: "translate(-50%, -50%)", bgcolor: "background.paper", p: 4, borderRadius: 3, textAlign: "center", boxShadow: 24 }}>
          <Typography variant="h6" sx={{ mb: 2 }}>Registration Successful!</Typography>
          <Typography>Please wait for admin approval.</Typography>
        </Box>
      </Modal>
    </Container>
  );
}
